#include <stdio.h>
#include <stdlib.h>

// Function to merge intervals
void mergeIntervals(int** intervals, int* newInterval, int intervalsSize, int* returnSize, int** resultDataOut) {
    int* resData = (int*)malloc(sizeof(int) * 2 * (intervalsSize + 1));
    int** resPtrs = (int**)malloc(sizeof(int*) * (intervalsSize + 1));
    int ri = 0;
    int i = 0;

    // Add intervals that end before newInterval starts
    while (i < intervalsSize && intervals[i][1] < newInterval[0]) {
        resData[2*ri + 0] = intervals[i][0];
        resData[2*ri + 1] = intervals[i][1];
        resPtrs[ri] = &resData[2*ri];
        ri++;
        i++;
    }

    // Merge overlapping intervals
    int start = newInterval[0];
    int end = newInterval[1];
    while (i < intervalsSize && intervals[i][0] <= end) {
        if (intervals[i][0] < start) start = intervals[i][0];
        if (intervals[i][1] > end) end = intervals[i][1];
        i++;
    }
    resData[2*ri + 0] = start;
    resData[2*ri + 1] = end;
    resPtrs[ri] = &resData[2*ri];
    ri++;

    // Add remaining intervals
    while (i < intervalsSize) {
        resData[2*ri + 0] = intervals[i][0];
        resData[2*ri + 1] = intervals[i][1];
        resPtrs[ri] = &resData[2*ri];
        ri++;
        i++;
    }

    *returnSize = ri;
    *resultDataOut = resData;
}

